import boto3
import json

def process_message(message):
    try:
        # Parse the message body
        message_body = json.loads(message.body)
        
        # Determine the type of message and execute corresponding action
        if 'type' in message_body:
            message_type = message_body['type']
            
            if message_type == 'task':
                task_id = message_body.get('id')
                print(f"Processing task: {task_id}")
                # Add your task processing logic here
                
            elif message_type == 'notification':
                user_id = message_body.get('user_id')
                message_content = message_body.get('content')
                print(f"Sending notification to user {user_id}: {message_content}")
                # Add your notification sending logic here
                
            else:
                print("Unknown message type")
        
        else:
            print("Invalid message format")
    
    except json.JSONDecodeError as e:
        print(f"Failed to decode JSON: {e}")
    except Exception as e:
        print(f"An error occurred: {e}")

def worker(queue_url):
    sqs = boto3.client('sqs')
    
    while True:
        # Poll for messages from the SQS queue
        response = sqs.receive_message(
            QueueUrl=queue_url,
            AttributeNames=['All'],
            MessageAttributeNames=['All'],
            MaxNumberOfMessages=10,
            WaitTimeSeconds=20
        )
        
        if 'Messages' in response:
            for message in response['Messages']:
                process_message(message)
                
                # Delete the message from the queue after processing
                sqs.delete_message(
                    QueueUrl=queue_url,
                    ReceiptHandle=message['ReceiptHandle']
                )

if __name__ == "__main__":
    queue_url = 'https://sqs.your-region.amazonaws.com/your-account-id/your-queue-name'
    worker(queue_url)